        solution: 'function removeScripts(html) {\n  return html.replace(/<script[^>]*>.*?<\\/script>/gi, \'\');\n}\n\nfunction removeEventHandlers(html) {\n  return html.replace(/\\s+on\\w+\\s*=\\s*(?:"[^"]*"|\'[^\']*\'|[^\\s>]+)/gi, \'\');\n}\n\nfunction removeJavascriptLinks(html) {\n  return html.replace(/href\\s*=\\s*(?:"javascript:[^"]*"|\'javascript:[^\']*\')/gi, \'href="#"\');\n}\n\nfunction sanitizeHtml(html) {\n  if (!html) return \'\';\n  let clean = removeScripts(html);\n  clean = removeEventHandlers(clean);\n  clean = removeJavascriptLinks(clean);\n  clean = clean.replace(/<iframe[^>]*>.*?<\\/iframe>/gi, \'\');\n  clean = clean.replace(/<object[^>]*>.*?<\\/object>/gi, \'\');\n  return clean;\n}',
