        solution: 'const ROLES = { ADMIN: \'admin\', EDITOR: \'editor\', USER: \'user\' };\nconst PERMISSIONS = {\n  [ROLES.ADMIN]: { users: [\'read\', \'write\', \'delete\'], posts: [\'read\', \'write\', \'delete\'] },\n  [ROLES.EDITOR]: { users: [\'read\'], posts: [\'read\', \'write\'] },\n  [ROLES.USER]: { users: [\'read\'], posts: [\'read\'] }\n};\n\nfunction authorize(action, resource) {\n  return (req, res, next) => {\n    const role = req.user && req.user.role;\n    if (!role) return res.status(401).json({ error: \'مطلوب تسجيل الدخول\' });\n    const perms = PERMISSIONS[role];\n    if (!perms || !perms[resource] || !perms[resource].includes(action)) {\n      return res.status(403).json({ error: \'غير مصرح بهذا الإجراء\' });\n    }\n    next();\n  };\n}\n\nfunction verifyOwnership(req, res, next) {\n  if (req.user.role !== \'admin\' && req.user.id !== req.params.id) {\n    return res.status(403).json({ error: \'لا يمكنك الوصول إلى هذا المورد\' });\n  }\n  next();\n}',
