          codeExample: '// تشغيل npm audit برمجياً\nconst { exec } = require(\'child_process\');\nconst util = require(\'util\');\nconst execPromise = util.promisify(exec);\n\nasync function auditDependencies() {\n  try {\n    const { stdout } = await execPromise(\'npm audit --json\');\n    return analyzeAudit(JSON.parse(stdout));\n  } catch (error) {\n    if (error.stdout) return analyzeAudit(JSON.parse(error.stdout));\n    throw error;\n  }\n}\n\nfunction analyzeAudit(auditResult) {\n  const issues = [];\n  for (const [, data] of Object.entries(auditResult.advisories || {})) {\n    issues.push({\n      package: data.module_name,\n      severity: data.severity,\n      title: data.title,\n      cve: data.cves[0] || \'N/A\',\n      patchedVersions: data.patched_versions\n    });\n  }\n  return issues.sort((a, b) => severityWeight(b.severity) - severityWeight(a.severity));\n}\n\nfunction severityWeight(s) { return { critical: 4, high: 3, moderate: 2, low: 1 }[s] || 0; }',
