        solution: 'const dependencies = {\n  \'express\': { version: \'4.16.0\', latest: \'4.18.2\' },\n  \'lodash\': { version: \'4.17.10\', latest: \'4.17.21\' },\n  \'axios\': { version: \'0.19.0\', latest: \'1.6.0\' }\n};\n\nfunction checkForOutdatedPackages(deps) {\n  const outdated = [];\n  for (const [name, info] of Object.entries(deps)) {\n    if (info.version !== info.latest) {\n      outdated.push({ name, current: info.version, latest: info.latest });\n    }\n  }\n  return outdated;\n}\n\nfunction generateDependencyReport(deps) {\n  const outdated = checkForOutdatedPackages(deps);\n  return {\n    total: Object.keys(deps).length,\n    outdatedCount: outdated.length,\n    packages: outdated,\n    summary: outdated.length === 0 ? \'جميع التبعيات محدثة\' : `${outdated.length} مكتبة قديمة`\n  };\n}',
