        solution: 'const loginAttempts = new Map();\nconst MAX_ATTEMPTS = 5;\nconst LOCKOUT_DURATION = 15 * 60 * 1000;\n\nfunction recordLoginAttempt(username, success) {\n  if (success) { loginAttempts.delete(username); return; }\n  const now = Date.now();\n  const attempts = loginAttempts.get(username) || [];\n  const recent = attempts.filter(t => now - t < LOCKOUT_DURATION);\n  recent.push(now);\n  loginAttempts.set(username, recent);\n}\n\nfunction isAccountLocked(username) {\n  const attempts = loginAttempts.get(username);\n  if (!attempts) return false;\n  const recent = attempts.filter(t => Date.now() - t < LOCKOUT_DURATION);\n  return recent.length >= MAX_ATTEMPTS;\n}\n\nfunction loginMiddleware(req, res, next) {\n  const { username } = req.body;\n  if (isAccountLocked(username)) {\n    return res.status(429).json({ error: \'الحساب مقفل مؤقتاً. حاول بعد 15 دقيقة.\' });\n  }\n  next();\n}',
