          codeExample: '// التحقق من سلامة الملفات\nconst crypto = require(\'crypto\');\nconst fs = require(\'fs\');\n\nfunction verifyFileIntegrity(filePath, expectedHash) {\n  return new Promise((resolve) => {\n    const hash = crypto.createHash(\'sha256\');\n    const stream = fs.createReadStream(filePath);\n    stream.on(\'data\', d => hash.update(d));\n    stream.on(\'end\', () => resolve(hash.digest(\'hex\') === expectedHash));\n    stream.on(\'error\', () => resolve(false));\n  });\n}\n\nfunction auditPackageIntegrity(packageLock) {\n  const issues = [];\n  const packages = packageLock.packages || {};\n  for (const [pkg, info] of Object.entries(packages)) {\n    if (info.link || info.bundled) continue;\n    if (!info.integrity) {\n      issues.push({ package: pkg, severity: \'high\', issue: \'لا يوجد checksum integrity\' });\n    }\n    if (info.resolved && info.resolved.startsWith(\'http://\')) {\n      issues.push({ package: pkg, severity: \'critical\', issue: \'مصدر تحميل غير آمن\' });\n    }\n  }\n  return issues;\n}',
