        solution: 'function verifyChecksum(filePath, expectedHash) {\n  return new Promise((resolve) => {\n    const hash = crypto.createHash(\'sha256\');\n    const stream = fs.createReadStream(filePath);\n    stream.on(\'data\', d => hash.update(d));\n    stream.on(\'end\', () => resolve(hash.digest(\'hex\') === expectedHash));\n    stream.on(\'error\', () => resolve(false));\n  });\n}\n\nfunction auditIntegrity(packageLock) {\n  const issues = [];\n  for (const [pkg, info] of Object.entries(packageLock.packages || {})) {\n    if (!info.integrity) issues.push({ pkg, issue: \'بدون checksum\' });\n    if (info.resolved && info.resolved.startsWith(\'http://\')) issues.push({ pkg, issue: \'مصدر غير آمن\' });\n  }\n  return issues;\n}',
