          starterCode: 'const ALLOWED_DOMAINS = [\'api.safe.com\', \'cdn.safe.com\'];\n\nfunction isValidUrl(url) {\n  // Your code here\n}\n\nfunction isPrivateIp(hostname) {\n  // Your code here\n}\n\nfunction safeRequest(url) {\n  if (!isValidUrl(url)) {\n    throw new Error(\'URL غير مسموح به\');\n  }\n  // Your code here - أرسل الطلب\n}',
