        solution: 'const { URL } = require(\'url\');\nconst ALLOWED_DOMAINS = [\'api.safe.com\', \'cdn.safe.com\'];\n\nfunction isValidUrl(url) {\n  try {\n    const parsed = new URL(url);\n    if (![\'http:\', \'https:\'].includes(parsed.protocol)) return false;\n    return ALLOWED_DOMAINS.some(d => parsed.hostname.endsWith(d));\n  } catch { return false; }\n}\n\nfunction isPrivateIp(hostname) {\n  const privatePatterns = [\'127.\', \'10.\', \'172.16.\', \'172.17.\', \'172.18.\', \'172.19.\', \'172.20.\', \'172.21.\', \'172.22.\', \'172.23.\', \'172.24.\', \'172.25.\', \'172.26.\', \'172.27.\', \'172.28.\', \'172.29.\', \'172.30.\', \'172.31.\', \'192.168.\', \'169.254.\', \'0.\', \'::1\', \'localhost\'];\n  return privatePatterns.some(p => hostname.startsWith(p) || hostname === p);\n}\n\nfunction safeRequest(url) {\n  const parsed = new URL(url);\n  if (!isValidUrl(url) || isPrivateIp(parsed.hostname)) {\n    throw new Error(\'URL غير مسموح به\' + (isPrivateIp(parsed.hostname) ? \' - عنوان داخلي\' : \'\'));\n  }\n  return fetch(url);\n}',
