        solution: 'app.post(\'/api/login\', loginLimiter, async (req, res) => {\n  const { username, password } = req.body;\n  const user = await findUser(username);\n  if (!user || !(await bcrypt.compare(password, user.passwordHash))) {\n    return res.status(401).json({ error: \'بيانات غير صحيحة\' });\n  }\n  const accessToken = jwt.sign({ userId: user.id }, process.env.JWT_SECRET, { expiresIn: \'15m\' });\n  const refreshToken = jwt.sign({ userId: user.id }, process.env.REFRESH_SECRET, { expiresIn: \'7d\' });\n  refreshTokens.add(refreshToken);\n  res.json({ accessToken, refreshToken });\n});\n\napp.post(\'/api/refresh\', async (req, res) => {\n  const { refreshToken } = req.body;\n  if (!refreshTokens.has(refreshToken)) return res.status(401).json({ error: \'غير صالح\' });\n  try {\n    const decoded = jwt.verify(refreshToken, process.env.REFRESH_SECRET);\n    const accessToken = jwt.sign({ userId: decoded.userId }, process.env.JWT_SECRET, { expiresIn: \'15m\' });\n    res.json({ accessToken });\n  } catch { res.status(401).json({ error: \'منتهي\' }); }\n});\n\napp.post(\'/api/logout\', (req, res) => {\n  refreshTokens.delete(req.body.refreshToken);\n  res.json({ message: \'تم تسجيل الخروج\' });\n});',
