        solution: 'app.post(\'/api/forgot-password\', async (req, res) => {\n  const { email } = req.body;\n  const user = await findUserByEmail(email);\n  if (user) {\n    const token = crypto.randomBytes(32).toString(\'hex\');\n    await storeResetToken(user.id, token, Date.now() + 3600000);\n    await sendResetEmail(email, token);\n  }\n  res.json({ message: \'إذا كان البريد الإلكتروني مسجلاً، ستتلقى رابط إعادة تعيين\' });\n});\n\napp.post(\'/api/reset-password\', async (req, res) => {\n  const { token, newPassword } = req.body;\n  if (newPassword.length < 8) return res.status(400).json({ error: \'قصيرة جداً\' });\n  const reset = await findResetToken(token);\n  if (!reset || reset.expiresAt < Date.now() || reset.used) {\n    return res.status(400).json({ error: \'رابط غير صالح\' });\n  }\n  const hash = await bcrypt.hash(newPassword, 12);\n  await updatePassword(reset.userId, hash);\n  await invalidateResetToken(token);\n  res.json({ message: \'تم إعادة التعيين بنجاح\' });\n});',
