          starterCode: 'app.use(cors({ /* Your code here */ }));\n\nconst apiLimiter = rateLimit({ /* Your code here */ });\n\nfunction authenticate(req, res, next) {\n  // Your code here\n}\n\napp.get(\'/api/protected\', authenticate, (req, res) => {\n  res.json({ message: \'هذه نقطة محمية\' });\n});',
