        solution: 'const corsOptions = { origin: [\'https://example.com\'], methods: [\'GET\', \'POST\'], allowedHeaders: [\'Content-Type\', \'Authorization\'] };\napp.use(cors(corsOptions));\n\nconst apiLimiter = rateLimit({ windowMs: 900000, max: 100 });\napp.use(\'/api/\', apiLimiter);\n\nfunction authenticate(req, res, next) {\n  const token = req.headers.authorization?.split(\' \')[1];\n  if (!token) return res.status(401).json({ error: \'مطلوب مصادقة\' });\n  try {\n    req.user = jwt.verify(token, process.env.JWT_SECRET);\n    next();\n  } catch { res.status(401).json({ error: \'رمز غير صالح\' }); }\n}',
