          codeExample: '// تسجيل منظم للأحداث\nconst winston = require(\'winston\');\n\nconst logger = winston.createLogger({\n  level: \'info\',\n  format: winston.format.combine(\n    winston.format.timestamp(),\n    winston.format.errors({ stack: true }),\n    winston.format.json()\n  ),\n  defaultMeta: { service: \'my-app\' },\n  transports: [\n    new winston.transports.File({ filename: \'logs/error.log\', level: \'error\' }),\n    new winston.transports.File({ filename: \'logs/combined.log\' })\n  ]\n});\n\nif (process.env.NODE_ENV !== \'production\') {\n  logger.add(new winston.transports.Console({\n    format: winston.format.simple()\n  }));\n}\n\n// استخدام آمن - لا تسجل بيانات حساسة\napp.post(\'/api/login\', async (req, res) => {\n  const { username } = req.body;\n  try {\n    await authenticate(req.body);\n    logger.info(\'تسجيل دخول ناجح\', { username, ip: req.ip });\n    res.json({ success: true });\n  } catch (error) {\n    logger.warn(\'فشل تسجيل الدخول\', { username, ip: req.ip, error: error.message });\n    res.status(401).json({ error: \'بيانات غير صحيحة\' });\n  }\n});',
