        solution: 'class CorrelationEngine {\n  constructor(windowMs = 60000) {\n    this.events = [];\n    this.windowMs = windowMs;\n    this.rules = [];\n  }\n\n  addRule(rule) { this.rules.push(rule); }\n\n  addEvent(event) {\n    this.events.push({ ...event, time: Date.now() });\n    this.events = this.events.filter(e => Date.now() - e.time < this.windowMs);\n    \n    const alerts = [];\n    for (const rule of this.rules) {\n      const matching = this.events.filter(e => rule.match(e));\n      if (matching.length >= rule.threshold) {\n        alerts.push({ rule: rule.name, events: matching.length });\n        this.events = []; // reset after alert\n      }\n    }\n    return alerts;\n  }\n}',
