        solution: 'class SecurityMonitor {\n  constructor() {\n    this.metrics = { requests: 0, errors: 0, blocked: 0 };\n    setInterval(() => {\n      const report = this.generateReport();\n      if (report.alerts.length) console.warn(\'تنبيهات:\', report.alerts);\n    }, 60000);\n  }\n\n  trackRequest(req, status) {\n    this.metrics.requests++;\n    if (status >= 500) this.metrics.errors++;\n    if (this.isSuspicious(req)) this.metrics.blocked++;\n  }\n\n  isSuspicious(req) {\n    return req.path.includes(\'../\') || req.path.includes(\'<script>\') || req.path.includes(\'/etc/passwd\');\n  }\n\n  generateReport() {\n    const rate = this.metrics.errors / Math.max(this.metrics.requests, 1);\n    const alerts = [];\n    if (rate > 0.05) alerts.push(`معدل خطأ ${(rate*100).toFixed(1)}%`);\n    if (this.metrics.blocked > 10) alerts.push(`${this.metrics.blocked} طلب مشبوه`);\n    const report = { ...this.metrics, alerts };\n    this.metrics = { requests: 0, errors: 0, blocked: 0 };\n    return report;\n  }\n}',
