        solution: 'class Investigator {\n  constructor() {\n    this.evidence = [];\n    this.timeline = [];\n  }\n\n  collectEvidence(type, source, data) {\n    const item = {\n      id: crypto.randomUUID(),\n      type, source,\n      time: new Date().toISOString(),\n      data,\n      hash: crypto.createHash(\'sha256\').update(JSON.stringify(data)).digest(\'hex\')\n    };\n    this.evidence.push(item);\n    this.timeline.push({ time: item.time, event: `جمع ${type} من ${source}` });\n    return item;\n  }\n\n  analyzeLogs(logs, criteria) {\n    const filtered = logs.filter(l => Object.entries(criteria).every(([k, v]) => l[k] === v));\n    filtered.forEach(l => this.timeline.push({ time: l.timestamp, event: l.message }));\n    this.timeline.sort((a, b) => a.time.localeCompare(b.time));\n    return filtered;\n  }\n\n  verifyIntegrity() {\n    return this.evidence.every(e => {\n      const hash = crypto.createHash(\'sha256\').update(JSON.stringify(e.data)).digest(\'hex\');\n      return hash === e.hash;\n    });\n  }\n}',
