        solution: 'const patterns = [\n  { pattern: /(\'|")\\s*(OR|AND)\\s*(\'|")/i, type: \'SQLi\' },\n  { pattern: /<script[^>]*>/i, type: \'XSS\' },\n  { pattern: /\\.\\.\\//, type: \'PathTraversal\' },\n  { pattern: /(UNION|SELECT|DROP).*FROM/i, type: \'SQLi\' }\n];\n\nfunction detectThreats(req) {\n  const text = req.path + \' \' + JSON.stringify(req.query) + \' \' + JSON.stringify(req.body);\n  return patterns.filter(p => p.pattern.test(text)).map(p => p.type);\n}\n\napp.use((req, res, next) => {\n  const threats = detectThreats(req);\n  if (threats.length) {\n    console.warn(\'تهديد:\', threats, \'من:\', req.ip);\n    if (threats.includes(\'SQLi\') || threats.includes(\'XSS\')) {\n      return res.status(403).json({ error: \'طلب مرفوض\' });\n    }\n  }\n  next();\n});',
