          codeExample: '// كشف محاولات الدخول المفرطة\nclass LoginDetector {\n  constructor() {\n    this.attempts = new Map();\n  }\n\n  recordAttempt(identifier, ip, success) {\n    const key = `${identifier}:${ip}`;\n    const now = Date.now();\n    \n    if (!this.attempts.has(key)) {\n      this.attempts.set(key, []);\n    }\n    \n    const userAttempts = this.attempts.get(key);\n    userAttempts.push({ time: now, success });\n    \n    // احتفظ فقط بآخر 60 دقيقة\n    const recent = userAttempts.filter(a => now - a.time < 3600000);\n    this.attempts.set(key, recent);\n    \n    return this.analyze(key, recent);\n  }\n\n  analyze(key, recent) {\n    const failed = recent.filter(a => !a.success);\n    const total = recent.length;\n    \n    if (failed.length >= 20) {\n      return { action: \'LOCK_ADMIN\', severity: \'critical\', message: \'قفل الحساب - مراجعة المسؤول مطلوبة\' };\n    }\n    if (failed.length >= 10) {\n      return { action: \'LOCK_15M\', severity: \'high\', message: \'قفل الحساب 15 دقيقة\' };\n    }\n    if (failed.length >= 5) {\n      return { action: \'CAPTCHA\', severity: \'medium\', message: \'طلب CAPTCHA\' };\n    }\n    if (failed.length >= 3) {\n      return { action: \'DELAY\', severity: \'low\', message: \'تأخير الاستجابة 2 ثانية\' };\n    }\n    \n    return { action: \'ALLOW\', severity: \'info\', message: \'مسموح\' };\n  }\n\n  // كشف حشو البيانات (نفس IP، مستخدمين مختلفين)\n  detectCredentialStuffing(ip) {\n    const now = Date.now();\n    let count = 0;\n    for (const [key, attempts] of this.attempts) {\n      if (key.endsWith(`:${ip}`)) {\n        count += attempts.filter(a => now - a.time < 60000).length;\n      }\n    }\n    return count > 30 ? { detected: true, attempts: count } : { detected: false };\n  }\n}',
