        solution: 'class LoginMonitor {\n  constructor() {\n    this.attempts = new Map();\n  }\n\n  recordAttempt(username, success) {\n    if (!this.attempts.has(username)) this.attempts.set(username, []);\n    const list = this.attempts.get(username);\n    list.push({ time: Date.now(), success });\n    this.attempts.set(username, list.filter(a => Date.now() - a.time < 3600000));\n  }\n\n  getAction(username) {\n    const attempts = this.attempts.get(username) || [];\n    const failed = attempts.filter(a => !a.success).length;\n    if (failed >= 10) return { action: \'LOCK\', message: \'مقفول 15 دقيقة\' };\n    if (failed >= 5) return { action: \'CAPTCHA\', message: \'مطلوب تحقق\' };\n    if (failed >= 3) return { action: \'DELAY\', message: \'تأخير\' };\n    return { action: \'ALLOW\' };\n  }\n}',
