          starterCode: 'class BehaviorMonitor {\n  constructor() { this.profiles = new Map(); }\n  \n  learn(userId, activity) {\n    // Your code here\n  }\n  \n  detect(userId, activity) {\n    // Your code here\n  }\n}',
