        solution: 'class BehaviorMonitor {\n  constructor() { this.profiles = new Map(); }\n\n  learn(userId, { ip, path, hour }) {\n    if (!this.profiles.has(userId)) {\n      this.profiles.set(userId, { hours: new Set(), ips: new Set(), endpoints: {} });\n    }\n    const p = this.profiles.get(userId);\n    p.hours.add(hour);\n    p.ips.add(ip);\n    p.endpoints[path] = (p.endpoints[path] || 0) + 1;\n  }\n\n  detect(userId, { ip, hour, path }) {\n    const p = this.profiles.get(userId);\n    if (!p || p.hours.size < 5) return null;\n    const issues = [];\n    if (!p.hours.has(hour)) issues.push({ type: \'time\', severity: \'medium\' });\n    if (!p.ips.has(ip)) issues.push({ type: \'ip\', severity: \'low\' });\n    return issues.length ? issues : null;\n  }\n}',
