        solution: 'class BotDetector {\n  constructor() {\n    this.visits = new Map();\n  }\n\n  analyze(req) {\n    let score = 0;\n    const reasons = [];\n    const ua = (req.headers[\'user-agent\'] || \'\').toLowerCase();\n    if (!ua || ua.length < 15) { score += 30; reasons.push(\'UA قصير أو مفقود\'); }\n    if (/curl|wget|python|scrapy/.test(ua)) { score += 40; reasons.push(\'UA بوت\'); }\n    const ipVisits = this.visits.get(req.ip) || [];\n    const now = Date.now();\n    ipVisits.push(now);\n    const recent = ipVisits.filter(t => now - t < 1000);\n    if (recent.length > 5) { score += 25; reasons.push(\'سرعة بوت\'); }\n    this.visits.set(req.ip, ipVisits.filter(t => now - t < 60000));\n    return { score, isBot: score > 50, reasons };\n  }\n\n  getAction(score) {\n    if (score > 80) return \'BLOCK\';\n    if (score > 50) return \'CAPTCHA\';\n    if (score > 30) return \'MONITOR\';\n    return \'ALLOW\';\n  }\n}',
