        solution: 'class BruteForceDetector {\n  constructor() {\n    this.ipMap = new Map();\n    this.userMap = new Map();\n  }\n\n  recordAttempt(ip, username) {\n    const now = Date.now();\n    if (!this.ipMap.has(ip)) this.ipMap.set(ip, []);\n    if (!this.userMap.has(username)) this.userMap.set(username, []);\n    this.ipMap.get(ip).push({ time: now, username });\n    this.userMap.get(username).push({ time: now, ip });\n  }\n\n  detectAttack(ip, username) {\n    this.recordAttempt(ip, username);\n    const now = Date.now();\n    const ipRecent = (this.ipMap.get(ip) || []).filter(a => now - a.time < 60000);\n    const userRecent = (this.userMap.get(username) || []).filter(a => now - a.time < 300000);\n    if (ipRecent.length > 20) return \'BLOCK_IP\';\n    if (new Set(userRecent.map(a => a.ip)).size > 5) return \'LOCK_USER\';\n    if (ipRecent.length > 5 && ipRecent.every((a, i, arr) => i === 0 || Math.abs(a.time - arr[i-1].time) < 100)) return \'BLOCK_IP\';\n    return \'ALLOW\';\n  }\n}',
