        hints: ['العلامة الأهم: عدة مستخدمين مختلفين (محاولة واحدة لكل منهم) من IP واحد', 'استخدم SHA-256 hash لمقارنة كلمات المرور بقوائم التسريبات', 'احسب درجة ثقة بناءً على عدد العلامات المكتشفة'],
        solution: 'class StuffingDetector {\n  constructor() {\n    this.ipUsers = new Map();\n    this.compromised = new Set();\n  }\n\n  addCompromised(password) {\n    this.compromised.add(crypto.createHash(\'sha256\').update(password).digest(\'hex\'));\n  }\n\n  analyze(ip, username, password) {\n    if (!this.ipUsers.has(ip)) this.ipUsers.set(ip, new Set());\n    this.ipUsers.get(ip).add(username);\n    const pwHash = crypto.createHash(\'sha256\').update(password).digest(\'hex\');\n    const flags = [];\n    if (this.ipUsers.get(ip).size > 5) flags.push(\'multi_user\');\n    if (this.compromised.has(pwHash)) flags.push(\'compromised_pw\');\n    return { isAttack: flags.length >= 2, flags, confidence: flags.length * 50 };\n  }\n}',
        realWorldUse: 'AT&T و Sony PlayStation تعرضتا لهجمات حشو بيانات. Cloudflare و Akamai توفرون حماية متخصصة.',
