        hints: ['استخدم nodemailer مع SMTP آمن (port 465)', 'طبق cooldown 5 دقائق لكل نوع تنبيه', 'استخدم ألواناً مختلفة حسب الخطورة'],
        solution: 'const nodemailer = require(\'nodemailer\');\nclass EmailAlert {\n  constructor(config) {\n    this.transporter = nodemailer.createTransport({ host: config.host, port: 465, secure: true, auth: { user: config.user, pass: config.pass } });\n    this.cooldowns = new Map();\n  }\n  async sendAlert(alert) {\n    const key = alert.type;\n    if (this.cooldowns.has(key) && Date.now() - this.cooldowns.get(key) < 300000) return;\n    await this.transporter.sendMail({ from: this.from, to: this.to, subject: `[${alert.severity}] ${alert.title}`, html: this.formatHtml(alert) });\n    this.cooldowns.set(key, Date.now());\n  }\n  formatHtml(a) { return `<div style="color:${a.severity===\'critical\'?\'red\':\'orange\'}"><h2>${a.title}</h2><p>${a.details}</p></div>`; }\n}',
