        solution: 'class Dashboard {\n  constructor() { this.alerts = []; this.stats = { total: 0, critical: 0, high: 0, medium: 0 }; this.listeners = new Set(); }\n  addAlert(alert) {\n    this.alerts.unshift({ ...alert, id: crypto.randomUUID(), time: new Date().toISOString() });\n    if (this.alerts.length > 1000) this.alerts.pop();\n    this.stats.total++;\n    this.stats[alert.severity || \'low\']++;\n    this.listeners.forEach(l => l(alert));\n  }\n  getFiltered(f) {\n    return this.alerts.filter(a => (!f.severity || a.severity === f.severity) && (!f.search || a.title.includes(f.search))).slice(0, f.limit || 100);\n  }\n  getStats() { return { ...this.stats }; }\n  subscribe(cb) { this.listeners.add(cb); return () => this.listeners.delete(cb); }\n}',
