        solution: 'class SimpleHoneypot {\n  constructor() {\n    this.logs = [];\n  }\n  listen(port) {\n    const server = net.createServer(s => {\n      const conn = { ip: s.remoteAddress, commands: [], start: Date.now() };\n      s.on(\'data\', d => { conn.commands.push(d.toString()); });\n      s.on(\'close\', () => { conn.end = Date.now(); this.logs.push(conn); this.logAttacker(conn); });\n      s.on(\'error\', () => s.destroy());\n    });\n    server.listen(port);\n  }\n  logAttacker(conn) {\n    fs.appendFileSync(\'honeypot.json\', JSON.stringify(conn) + \'\\n\');\n  }\n}',
