          codeExample: '// صفحة تسجيل دخول مزيفة\nconst express = require(\'express\');\nconst app = express();\n\napp.get(\'/login\', (req, res) => {\n  res.send(`\n    <html dir="rtl">\n    <head><title>تسجيل الدخول - لوحة الإدارة</title>\n    <style>\n      body { font-family: sans-serif; display: flex; justify-content: center; align-items: center; height: 100vh; background: #f3f4f6; }\n      .login-form { background: white; padding: 40px; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.1); width: 400px; }\n      h1 { text-align: center; color: #1f2937; margin-bottom: 30px; }\n      input { width: 100%; padding: 12px; margin: 8px 0; border: 1px solid #d1d5db; border-radius: 4px; box-sizing: border-box; }\n      button { width: 100%; padding: 12px; background: #2563eb; color: white; border: none; border-radius: 4px; cursor: pointer; font-size: 16px; }\n      .error { color: #dc2626; text-align: center; margin-top: 10px; display: none; }\n    </style>\n    </head>\n    <body>\n      <div class="login-form">\n        <h1>لوحة الإدارة</h1>\n        <form action="/api/login" method="POST">\n          <input type="text" name="username" placeholder="اسم المستخدم" required>\n          <input type="password" name="password" placeholder="كلمة المرور" required>\n          <input type="hidden" name="csrf_token" value="lol">\n          <button type="submit">تسجيل الدخول</button>\n        </form>\n        <div class="error">بيانات الدخول غير صحيحة</div>\n      </div>\n      <script>\n        document.querySelector(\'form\').onsubmit = async (e) => {\n          e.preventDefault();\n          await fetch(\'/api/login\', { method: \'POST\', body: new FormData(e.target) });\n          document.querySelector(\'.error\').style.display = \'block\';\n        };\n      </script>\n    </body>\n    </html>\n  `);\n});\n\napp.post(\'/api/login\', (req, res) => {\n  const { username, password } = req.body;\n  \n  // تسجيل محاولة الدخول\n  const attempt = {\n    timestamp: new Date().toISOString(),\n    ip: req.ip,\n    userAgent: req.headers[\'user-agent\'],\n    username,\n    password,\n    headers: req.headers\n  };\n  \n  fs.appendFileSync(\'honeypot-logins.log\', JSON.stringify(attempt) + \'\\n\');\n  \n  // كشف الأدوات\n  const isBot = this.detectTool(req);\n  if (isBot) {\n    fs.appendFileSync(\'honeypot-bots.log\', JSON.stringify({ ...attempt, tool: isBot }) + \'\\n\');\n  }\n  \n  res.status(401).json({ error: \'بيانات غير صحيحة\' });\n});\n\nfunction detectTool(req) {\n  const ua = req.headers[\'user-agent\'] || \'\';\n  if (ua.includes(\'sqlmap\')) return \'sqlmap\';\n  if (ua.includes(\'hydra\')) return \'Hydra\';\n  if (ua.includes(\'nikto\')) return \'Nikto\';\n  if (!ua || ua.length < 20) return \'Generic Bot\';\n  return null;\n}',
