          codeExample: '// بوابة مشرف مزيفة\nconst fakeData = {\n  users: [\n    { id: 1, username: \'admin\', email: \'admin@example.com\', role: \'مدير النظام\', lastLogin: \'2024-01-15\' },\n    { id: 2, username: \'editor\', email: \'editor@example.com\', role: \'محرر\', lastLogin: \'2024-01-14\' },\n    { id: 3, username: \'db_admin\', email: \'db@example.com\', role: \'مدير قاعدة بيانات\', lastLogin: \'2024-01-10\' }\n  ],\n  config: {\n    dbHost: \'192.168.1.100\',\n    dbName: \'production_db\',\n    apiEndpoint: \'https://api.internal.example.com\',\n    encryptionKey: \'-- FAKE KEY FOR HONEYPOT --\'\n  },\n  securityLogs: [\n    { action: \'تسجيل دخول من IP مشبوه\', ip: \'10.0.0.50\', time: \'2024-01-15 14:23:00\', status: \'تم الحظر\' },\n    { action: \'محاولة وصول إلى /etc/passwd\', ip: \'10.0.0.50\', time: \'2024-01-15 14:20:00\', status: \'تم التسجيل\' }\n  ]\n};\n\nclass FakeAdminPortal {\n  constructor() {\n    this.visitors = new Map();\n    this.sessionData = new Map();\n  }\n\n  trackVisitor(req) {\n    const sessionId = req.cookies?.honeypot_session || crypto.randomUUID();\n    if (!this.visitors.has(sessionId)) {\n      this.visitors.set(sessionId, {\n        firstVisit: new Date().toISOString(),\n        pages: [],\n        clicks: [],\n        ip: req.ip,\n        userAgent: req.headers[\'user-agent\']\n      });\n    }\n    return sessionId;\n  }\n\n  trackPage(sessionId, page, data = {}) {\n    const visitor = this.visitors.get(sessionId);\n    if (visitor) {\n      visitor.pages.push({ page, time: new Date().toISOString(), data });\n    }\n  }\n\n  trackClick(sessionId, element, value) {\n    const visitor = this.visitors.get(sessionId);\n    if (visitor) {\n      visitor.clicks.push({ element, value, time: new Date().toISOString() });\n      \n      // إذا حاول المهاجم رفع ملف أو تعديل إعدادات\n      if (element === \'file_upload\' || element === \'config_edit\') {\n        this.generateAlert(visitor, element, value);\n      }\n    }\n  }\n\n  generateAlert(visitor, action, value) {\n    const alert = {\n      timestamp: new Date().toISOString(),\n      type: \'honeypot_interaction\',\n      ip: visitor.ip,\n      action,\n      value,\n      sessionDuration: Date.now() - new Date(visitor.firstVisit).getTime()\n    };\n    fs.appendFileSync(\'honeypot-alerts.log\', JSON.stringify(alert) + \'\\n\');\n  }\n\n  getDashboard(req) {\n    const sessionId = this.trackVisitor(req);\n    this.trackPage(sessionId, \'dashboard\');\n    \n    return {\n      stats: {\n        totalUsers: fakeData.users.length,\n        activeUsers: 3,\n        pendingAlerts: fakeData.securityLogs.length,\n        systemHealth: \'جيد\'\n      },\n      recentUsers: fakeData.users,\n      securityLogs: fakeData.securityLogs.slice(0, 5),\n      sessionId\n    };\n  }\n}',
