          starterCode: 'const apiHoneypot = (req, res, next) => {\n  // Your code here - سجل الطلب واكتشف الأداة\n  next();\n};\n\napp.get(\'/api/honeypot/users\', apiHoneypot, (req, res) => {\n  // Your code here - أعد بيانات مزيفة\n});',
