        solution: 'class HoneypotLogger {\n  constructor() { this.logs = []; }\n  log(type, data) {\n    const entry = { id: crypto.randomUUID(), type, time: new Date().toISOString(), data };\n    this.logs.push(entry);\n    fs.appendFileSync(\'honeypot.log\', JSON.stringify(entry) + \'\\n\');\n  }\n  query(filters) {\n    return this.logs.filter(e => (!filters.type || e.type === filters.type) && (!filters.ip || e.data.ip === filters.ip));\n  }\n  generateReport() {\n    return { total: this.logs.length, uniqueIps: new Set(this.logs.map(l => l.data?.ip)).size };\n  }\n}',
