        solution: 'class HoneypotAlerts {\n  constructor() { this.blocked = new Map(); }\n  \n  classify({ type, toolDetected, attempts }) {\n    const scores = { page_visit: 5, login_attempt: 20, command: 50, upload: 60, exploit: 80 };\n    return (scores[type] || 0) + (toolDetected ? 20 : 0) + (attempts > 10 ? 15 : 0);\n  }\n  \n  async process(interaction) {\n    const score = this.classify(interaction);\n    const action = score > 70 ? \'BLOCK_24H\' : score > 40 ? \'BLOCK_15M\' : score > 20 ? \'LOG\' : \'IGNORE\';\n    if (action !== \'IGNORE\') {\n      this.blocked.set(interaction.ip, { until: Date.now() + (action === \'BLOCK_24H\' ? 86400000 : 900000) });\n      if (score > 40) await this.sendAlert(interaction);\n    }\n  }\n  \n  isBlocked(ip) {\n    const b = this.blocked.get(ip);\n    if (!b) return false;\n    if (Date.now() > b.until) { this.blocked.delete(ip); return false; }\n    return true;\n  }\n}',
