          starterCode: 'class HoneypotAnalytics {\n  async getTopIps(limit) {\n    // Your code here\n  }\n  \n  async getTimeline(days) {\n    // Your code here\n  }\n  \n  async getPatterns() {\n    // Your code here\n  }\n}',
