        solution: 'class HoneypotAnalytics {\n  async getTopIps(limit = 10) {\n    const ipMap = new Map();\n    (await this.logger.query()).forEach(e => {\n      const ip = e.data?.ip;\n      if (ip) ipMap.set(ip, (ipMap.get(ip) || 0) + 1);\n    });\n    return [...ipMap.entries()].sort((a, b) => b[1] - a[1]).slice(0, limit).map(([ip, count]) => ({ ip, count }));\n  }\n  async getTimeline(days = 7) {\n    const tl = {};\n    (await this.logger.query()).filter(e => Date.now() - new Date(e.timestamp).getTime() < days * 86400000).forEach(e => {\n      const d = e.timestamp.split(\'T\')[0];\n      tl[d] = (tl[d] || 0) + 1;\n    });\n    return tl;\n  }\n  async getPatterns() {\n    const h = Array(24).fill(0);\n    (await this.logger.query()).forEach(e => { h[new Date(e.timestamp).getHours()]++; });\n    return { hourly: h };\n  }\n}',
