          codeExample: '// نظام تسجيل النشاط المشبوه\nclass ActivityScorer {\n  constructor(thresholds) {\n    this.thresholds = thresholds;\n    this.scores = new Map();\n    this.history = new Map();\n  }\n\n  recordActivity(userId, activity, context) {\n    const weight = this.getWeight(activity, context);\n    const currentScore = this.scores.get(userId) || { total: 0, events: [], windowStart: Date.now() };\n\n    if (Date.now() - currentScore.windowStart > 3600000) {\n      currentScore.total = 0;\n      currentScore.events = [];\n      currentScore.windowStart = Date.now();\n    }\n\n    currentScore.total += weight;\n    currentScore.events.push({ activity, weight, timestamp: Date.now() });\n    this.scores.set(userId, currentScore);\n\n    if (!this.history.has(userId)) this.history.set(userId, []);\n    this.history.get(userId).push({ total: currentScore.total, timestamp: Date.now() });\n\n    return {\n      userId,\n      score: currentScore.total,\n      threshold: this.getThreshold(userId),\n      alerted: currentScore.total > this.getThreshold(userId),\n      recentEvents: currentScore.events.slice(-5)\n    };\n  }\n\n  getWeight(activity, context) {\n    const weights = {\n      login_failure: 5,\n      password_change: 10,\n      new_location: 15,\n      large_transfer: 30,\n      api_abuse: 25\n    };\n    return weights[activity] || 1;\n  }\n\n  getThreshold(userId) {\n    const history = this.history.get(userId) || [];\n    if (history.length < 10) return this.thresholds.default;\n    const avg = history.slice(-20).reduce((sum, h) => sum + h.total, 0) / Math.min(20, history.length);\n    return Math.max(this.thresholds.min, avg * 2);\n  }\n}',
