        solution: "function createActivityScorer(defaultThreshold) {\n  const scores = {};\n  const weights = { login_failure: 5, password_change: 10, new_location: 15, large_transfer: 30 };\n  const WINDOW_MS = 30 * 60 * 1000;\n\n  function getOrCreate(userId) {\n    if (!scores[userId] || Date.now() - scores[userId].windowStart > WINDOW_MS) {\n      scores[userId] = { total: 0, events: [], windowStart: Date.now() };\n    }\n    return scores[userId];\n  }\n\n  return {\n    record(userId, activity) {\n      const user = getOrCreate(userId);\n      const weight = weights[activity] || 1;\n      user.total += weight;\n      user.events.push({ activity, weight, time: Date.now() });\n      const threshold = defaultThreshold;\n      return { userId, score: user.total, threshold, alerted: user.total > threshold, recentEvents: user.events.slice(-3) };\n    }\n  };\n}",
