          codeExample: "// محرك توليد التنبيهات التلقائي\nclass AlertEngine {\n  constructor(rules, notifiers) {\n    this.rules = rules;\n    this.notifiers = notifiers;\n    this.alertHistory = [];\n  }\n\n  evaluate(event) {\n    const triggered = [];\n    for (const rule of this.rules) {\n      if (rule.condition(event)) {\n        const alert = {\n          id: `AL-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,\n          ruleId: rule.id,\n          severity: rule.severity,\n          title: rule.title,\n          description: rule.description(event),\n          timestamp: new Date().toISOString(),\n          source: event.source,\n          raw: event\n        };\n        this.alertHistory.push(alert);\n        this.dispatchAlert(alert, rule.notify);\n        triggered.push(alert);\n      }\n    }\n    return triggered;\n  }\n\n  dispatchAlert(alert, channels) {\n    for (const channel of channels) {\n      const notifier = this.notifiers[channel];\n      if (notifier) notifier.send(alert);\n    }\n  }\n\n  getAlerts(filters = {}) {\n    return this.alertHistory.filter(a => {\n      return (!filters.severity || a.severity === filters.severity) &&\n             (!filters.since || new Date(a.timestamp) > filters.since);\n    });\n  }\n}\n\n// مثال على قاعدة\nconst bruteForceRule = {\n  id: 'BRUTE-001',\n  title: 'هجوم تخمين كلمة مرور',\n  severity: 'high',\n  condition: (event) => event.type === 'login_failure' && event.count > 10,\n  description: (event) => `تم رصد ${event.count} محاولة فاشلة من ${event.ip}`,\n  notify: ['email', 'slack']\n};",
