        hints: ['استخدم استبدال النص (String.replace) لملء المتغيرات في القالب', 'قسّم التقارير إلى: فني (مفصل) وإداري (موجز)', 'لتصدير HTML، لف المحتوى في هيكل HTML5 كامل'],
        solution: "function createReportGenerator(templates) {\n  function fill(template, data) {\n    return Object.entries(data).reduce((acc, [k, v]) => acc.replace(new RegExp(`{{${k}}}`, 'g'), v), template);\n  }\n  return {\n    generate(incident, format) {\n      const data = { id: incident.id, title: incident.title, date: new Date().toLocaleDateString('ar-SA'), severity: incident.severity, description: incident.description || '' };\n      if (format === 'technical') data.details = incident.events?.map(e => `- ${e}`).join('\\n') || '';\n      if (format === 'executive') data.impact = incident.businessImpact || 'غير محدد';\n      return fill(templates[format] || '', data);\n    },\n    exportToHTML(report) { return `<!DOCTYPE html><html dir=\"rtl\"><head><meta charset=\"UTF-8\"><title>تقرير حادث</title></head><body>${report}</body></html>`; },\n    exportToJSON(incident) { return JSON.stringify(incident, null, 2); }\n  };\n}",
        realWorldUse: 'منصات SOAR مثل Splunk SOAR و Palo Alto XSOAR تولد تقارير حوادث تلقائياً بعد كل استجابة. SOCs تستخدم هذه التقارير للامتثال وتحسين العمليات.',
