        hints: ['افصل مصدر البيانات عن طريقة العرض (MVC pattern)', 'استخدم setInterval للتحديث الدوري مع إمكانية الإيقاف', 'وفر طريقة للاشتراك (subscribe) للحصول على التحديثات'],
        solution: "function createDashboard(sources) {\n  const widgets = {};\n  const subscribers = [];\n  let timer = null;\n\n  return {\n    addWidget(name, renderFn) { widgets[name] = renderFn; },\n    async refresh() {\n      const data = {};\n      for (const [key, src] of Object.entries(sources)) {\n        try { data[key] = await src(); } catch (e) { data[key] = { error: e.message }; }\n      }\n      Object.entries(widgets).forEach(([key, fn]) => data[key] && fn(data[key]));\n      subscribers.forEach(fn => fn(data));\n      return data;\n    },\n    start(intervalMs) {\n      this.refresh();\n      timer = setInterval(() => this.refresh(), intervalMs || 10000);\n    },\n    subscribe(fn) { subscribers.push(fn); }\n  };\n}",
        realWorldUse: 'Splunk Dashboards و Grafana و Kibana هي أشهر منصات لوحات المعلومات الأمنية. تستخدمها الشركات لمراقبة الوضع الأمني في الوقت الفعلي عبر SOC.',
