        duration: '25 دقيقة',
        learningObjectives: [
          'فهم مفهوم تصفية الطلبات وأهميتها في حماية التطبيقات',
          'بناء قواعد تصفية على مستوى المسار والمعاملات والرؤوس',
          'تطبيق التصفية الإيجابية (whitelist) والسلبية (blacklist)',
          'اختبار فعالية قواعد التصفية ضد هجمات مختلفة',
        ],
        theory: {
          intro: 'تصفية الطلبات (Request Filtering) هي خط الدفاع الأول في WAF، حيث يتم فحص كل طلب وارد وتطبيق قواعد محددة للسماح أو المنع قبل وصول الطلب إلى التطبيق. التصفية الفعالة تمنع معظم الهجمات الشائعة.',
          sections: [
            { title: 'مستويات التصفية', content: 'المسار (Path): التحقق من صحة المسار المطلوب ومنع المسارات الحساسة. المعاملات (Parameters): فحص قيم المعاملات بحثاً عن أنماط ضارة. الرؤوس (Headers): التحقق من رؤوس HTTP ومنع الرؤوس المشبوهة. الجسم (Body): فحص محتوى الطلب للبيانات الضارة.' },
            { title: 'التصفية الإيجابية vs السلبية', content: 'التصفية الإيجابية (Positive Security): تسمح فقط بالأنماط المعروفة والمسموحة، وترفض كل شيء آخر. التصفية السلبية (Negative Security): تمنع الأنماط المعروفة بالضارة وتسمح بكل شيء آخر. يفضل استخدام كلا النوعين معاً.' },
            { title: 'أنماط التصفية الشائعة', content: 'منع المسارات الإدارية (/admin, /wp-admin)، منع أنواع ملفات خطيرة (.exe, .sh, .sql)، منع طرق HTTP غير المرغوب فيها (PUT, DELETE للمستخدمين العاديين)، منع الرؤوس المشبوهة (X-Forwarded-For مزيفة).' },
          ],
          codeExample: '// نظام تصفية الطلبات\nclass RequestFilter {\n  constructor() {\n    this.rules = {\n      blockedPaths: [/\\/admin/i, /\\/config\\./i, /\\/\\.env/i],\n      blockedExtensions: [\'\\.exe$\', \'\\.sh$\', \'\\.sql$\', \'\\.bak$\'],\n      allowedMethods: [\'GET\', \'POST\', \'PUT\', \'DELETE\'],\n      maxBodySize: 1024 * 1024,\n      maxParamLength: 1024,\n    };\n  }\n  filter(request) {\n    const violations = [];\n    if (this.rules.blockedPaths.some(p => p.test(request.path))) violations.push(\'المسار محظور\');\n    if (this.rules.blockedExtensions.some(e => new RegExp(e, \'i\').test(request.path))) violations.push(\'امتداد الملف محظور\');\n    if (!this.rules.allowedMethods.includes(request.method)) violations.push(\'طريقة HTTP غير مسموحة\');\n    if (request.body && request.body.length > this.rules.maxBodySize) violations.push(\'حجم الطلب كبير جداً\');\n    return { allowed: violations.length === 0, violations };\n  }\n}',
        },
        exercise: {
          instructions: [
            'أنشئ نظام تصفية طلبات يمنع المسارات الإدارية',
            'أضف منع لأنواع الملفات الخطيرة (.exe, .sh, .sql)',
            'نفذ التحقق من طرق HTTP المسموحة فقط',
            'أضف حداً أقصى لحجم الطلب (2MB) وطول المعاملات (2048 حرف)',
          ],
          starterCode: 'function createRequestFilter(config) {\n  // أكمل نظام التصفية\n  \n  return function filter(request) {\n    // افحص الطلب وأعد النتيجة\n  };\n}',
          expectedOutput: '{ allowed: false, violations: ["المسار محظور", "امتداد الملف محظور"], requestId: "req-123" }',
        },
        validationChecks: [
          { id: 'check-1', label: 'يمنع المسارات الإدارية', check: (code) => code.includes('admin') || code.includes('config') },
          { id: 'check-2', label: 'يمنع الامتدادات الخطيرة', check: (code) => code.includes('.exe') || code.includes('.sh') || code.includes('.sql') },
          { id: 'check-3', label: 'يتحقق من حجم الطلب', check: (code) => code.includes('bodySize') || code.includes('length') },
        ],
        hints: ['استخدم RegExp لمطابقة الأنماط في المسارات', 'تأكد من التحقق من طول المعاملات قبل معالجتها', 'استخدم قائمة بيضاء للطرق المسموحة بدلاً من القائمة السوداء'],
        solution: 'function createRequestFilter(config) {\n  const blockedPaths = config.blockedPaths || [/\\/admin/i, /\\/config/i, /\\/\\.env/i];\n  const blockedExts = config.blockedExtensions || [\'\\.exe$\', \'\\.sh$\', \'\\.sql$\', \'\\.bak$\'];\n  const allowedMethods = config.allowedMethods || [\'GET\', \'POST\', \'PUT\', \'DELETE\'];\n  const maxBodySize = config.maxBodySize || 2 * 1024 * 1024;\n  const maxParamLength = config.maxParamLength || 2048;\n  return function filter(request) {\n    const violations = [];\n    if (blockedPaths.some(p => new RegExp(p, \'i\').test(request.path))) violations.push(\'المسار محظور\');\n    if (blockedExts.some(e => new RegExp(e, \'i\').test(request.path))) violations.push(\'امتداد الملف محظور\');\n    if (!allowedMethods.includes(request.method)) violations.push(\'طريقة HTTP غير مسموحة\');\n    if (request.body && request.body.length > maxBodySize) violations.push(\'حجم الطلب كبير جداً\');\n    if (request.params && Object.values(request.params).some(v => v && v.length > maxParamLength)) violations.push(\'طول المعاملات كبير جداً\');\n    return { allowed: violations.length === 0, violations, requestId: request.id || \'unknown\' };\n  };\n}',
        realWorldUse: 'AWS WAF يسمح بإنشاء قواعد تصفية مخصصة للمسارات والرؤوس. Cloudflare WAF يوفر تصفية على مستوى الطبقة 7 مع دعم للتعبيرات المنتظمة.',
