        validationChecks: [
          { id: 'check-1', label: 'يطبق نافذة زمنية متحركة', check: (code) => code.includes('filter') || code.includes('window') },
          { id: 'check-2', label: 'يدعم سياسات مختلفة للمسارات', check: (code) => code.includes('path') || code.includes('policy') },
          { id: 'check-3', label: 'يرجع 429 عند تجاوز الحد', check: (code) => code.includes('429') || code.includes('retryAfter') },
        ],
        hints: ['استخدم Date.now() للحصول على الوقت الحالي', 'صفي الطوابع الزمنية الأقدم من النافذة قبل إضافة الجديد', 'احسب retryAfter من أقدم طابع زمني في النافذة'],
        solution: 'function createRateLimiter(policies) {\n  const clients = new Map();\n  return function checkRate(clientId, path, whitelist = []) {\n    if (whitelist.includes(clientId)) return { allowed: true, status: 200, remaining: Infinity };\n    const policy = policies[path] || policies.default || { windowMs: 60000, maxRequests: 60 };\n    const now = Date.now();\n    const key = `${clientId}:${path}`;\n    const timestamps = (clients.get(key) || []).filter(t => now - t < policy.windowMs);\n    if (timestamps.length >= policy.maxRequests) {\n      const retryAfter = Math.ceil((timestamps[0] + policy.windowMs - now) / 1000);\n      return { allowed: false, status: 429, retryAfter, remaining: 0, policy: path };\n    }\n    timestamps.push(now);\n    clients.set(key, timestamps);\n    return { allowed: true, status: 200, remaining: policy.maxRequests - timestamps.length, policy: path };\n  };\n}',
        realWorldUse: 'GitHub API يستخدم Rate Limiting بـ 5000 طلب/ساعة للمستخدمين المصادقين. Twitter API يسمح بـ 300 طلب/15 دقيقة. Stripe API يستخدم تحديد معدل لحماية endpoints الدفع.',
