          starterCode: 'function createRequestValidator() {\n  return {\n    validateSyntactic(data, schema) {\n      // تحقق من البنية والأنواع\n    },\n    validateSemantic(data, context) {\n      // تحقق من المعنى والمنطق\n    },\n    validate(data, schema, context) {\n      // تحقق كامل\n    },\n  };\n}',
          expectedOutput: '{ valid: false, errors: [{ field: "age", message: "يجب أن يكون العمر بين 13 و 120" }, { field: "email", message: "البريد الإلكتروني غير صالح" }] }',
