          starterCode: 'function createEventReviewer() {\n  const events = [];\n  const alerts = [];\n\n  return {\n    ingest(source, logEvents) {\n      // Your code here\n    },\n    correlate() {\n      // Your code here\n    },\n    getPriorities() {\n      // Your code here\n    },\n    getSummary() {\n      // Your code here\n    },\n  };\n}',
