        solution: 'function createEventReviewer() {\n  const events = [];\n  const alerts = [];\n  return {\n    ingest(source, logEvents) {\n      const normalized = logEvents.map(e => ({ id: e.id || Math.random().toString(36), source, timestamp: e.timestamp || new Date().toISOString(), type: e.type || \'unknown\', severity: e.severity || \'info\', data: e }));\n      events.push(...normalized);\n      const ipEvents = {};\n      normalized.forEach(e => {\n        const ip = e.data?.ip;\n        if (!ip) return;\n        if (!ipEvents[ip]) ipEvents[ip] = [];\n        ipEvents[ip].push(e);\n      });\n      Object.entries(ipEvents).forEach(([ip, evts]) => {\n        if (evts.length >= 3 && !alerts.find(a => a.ip === ip && Date.now() - a.timestamp < 300000)) {\n          alerts.push({ id: Math.random().toString(36), type: \'correlation\', severity: \'high\', ip, eventCount: evts.length, eventTypes: [...new Set(evts.map(e => e.type))], timestamp: Date.now() });\n        }\n      });\n      return { ingested: normalized.length, alerts: alerts.length };\n    },\n    correlate() { return alerts; },\n    getPriorities() {\n      const severityMap = { critical: 4, high: 3, medium: 2, low: 1, info: 0 };\n      return events.filter(e => e.severity !== \'info\').sort((a, b) => severityMap[b.severity] - severityMap[a.severity]);\n    },\n    getSummary() {\n      const sourceCounts = events.reduce((acc, e) => { acc[e.source] = (acc[e.source] || 0) + 1; return acc; }, {});\n      const priorityCounts = events.reduce((acc, e) => { acc[e.severity] = (acc[e.severity] || 0) + 1; return acc; }, {});\n      return { ingested: events.length, alerts: alerts.length, topSources: sourceCounts, priorityCounts };\n    }\n  };\n}',
