          starterCode: 'function createIRWorkflow() {\n  const workflows = {};\n  const activeIncidents = {};\n\n  return {\n    defineWorkflow(type, steps) {\n      // Your code here\n    },\n    execute(incident) {\n      // Your code here\n    },\n    getStatus(id) {\n      // Your code here\n    },\n  };\n}',
