        solution: 'function createIRWorkflow() {\n  const workflows = {};\n  const activeIncidents = {};\n  return {\n    defineWorkflow(type, steps) { workflows[type] = steps; },\n    execute(incident) {\n      const steps = workflows[incident.type];\n      if (!steps) return { status: \'error\', error: \'سير عمل غير معروف\' };\n      const log = [];\n      let status = \'completed\';\n      for (const step of steps) {\n        try {\n          step.action(incident);\n          log.push({ step: step.name, status: \'success\', timestamp: Date.now() });\n        } catch (e) {\n          log.push({ step: step.name, status: \'failed\', error: e.message, timestamp: Date.now() });\n          if (step.critical) { status = \'failed\'; break; }\n        }\n      }\n      activeIncidents[incident.id] = { ...incident, status, log };\n      return { incidentId: incident.id, type: incident.type, stepsCompleted: log.filter(l => l.status === \'success\').length, stepsFailed: log.filter(l => l.status === \'failed\').length, status, log };\n    },\n    getStatus(id) { return activeIncidents[id] || null; }\n  };\n}',
